import React from 'react';
import { PokemonWithStats } from '../types/pokemonChampions';

interface PokemonChampionCardProps {
  pokemon: PokemonWithStats;
  onClick: (pokemon: PokemonWithStats) => void;
  showPartyActions?: boolean;
  onAddToParty?: (pokemon: PokemonWithStats) => void;
  isSwapMode?: boolean;
  onSwapSelect?: (pokemon: PokemonWithStats) => void;
}

const PokemonChampionCard: React.FC<PokemonChampionCardProps> = ({ 
  pokemon, 
  onClick, 
  showPartyActions = false,
  onAddToParty,
  isSwapMode = false,
  onSwapSelect
}) => {
  const { champion, stats } = pokemon;

  const handleCardClick = (e: React.MouseEvent) => {
    if (showPartyActions && !isSwapMode && onAddToParty) {
      e.stopPropagation();
      onAddToParty(pokemon);
    } else if (isSwapMode && onSwapSelect) {
      e.stopPropagation();
      onSwapSelect(pokemon);
    } else if (onClick) {
      onClick(pokemon);
    }
  };

  const typeColors: Record<string, string> = {
    Normal: 'bg-gray-400 hover:bg-gray-500',
    Fire: 'bg-red-500 hover:bg-red-600',
    Water: 'bg-blue-500 hover:bg-blue-600',
    Electric: 'bg-yellow-400 hover:bg-yellow-500',
    Grass: 'bg-green-500 hover:bg-green-600',
    Ice: 'bg-cyan-400 hover:bg-cyan-500',
    Fighting: 'bg-red-700 hover:bg-red-800',
    Poison: 'bg-purple-500 hover:bg-purple-600',
    Ground: 'bg-yellow-600 hover:bg-yellow-700',
    Flying: 'bg-indigo-400 hover:bg-indigo-500',
    Psychic: 'bg-pink-500 hover:bg-pink-600',
    Bug: 'bg-lime-500 hover:bg-lime-600',
    Rock: 'bg-yellow-700 hover:bg-yellow-800',
    Ghost: 'bg-purple-700 hover:bg-purple-800',
    Dragon: 'bg-indigo-600 hover:bg-indigo-700',
    Dark: 'bg-gray-800 hover:bg-gray-900',
    Steel: 'bg-gray-600 hover:bg-gray-700',
    Fairy: 'bg-pink-400 hover:bg-pink-500',
  };

  const abilityColors: string[] = [
    'bg-orange-400 hover:bg-orange-500',
    'bg-teal-400 hover:bg-teal-500',
    'bg-amber-400 hover:bg-amber-500',
    'bg-rose-400 hover:bg-rose-500',
    'bg-sky-400 hover:bg-sky-500',
    'bg-emerald-400 hover:bg-emerald-500',
    'bg-violet-400 hover:bg-violet-500',
    'bg-fuchsia-400 hover:bg-fuchsia-500',
  ];

  const getAbilityColor = (abilityName: string) => {
    const hash = abilityName.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
    return abilityColors[hash % abilityColors.length];
  };

  const combatStats = [
    { name: 'ATK', value: stats.atk },
    { name: 'DEF', value: stats.def },
    { name: 'SP.ATK', value: stats.spa },
    { name: 'SP.DEF', value: stats.spd },
    { name: 'SPD', value: stats.spe }
  ];

  const getPokemonImageUrl = (name: string, dexNumber: number) => {
    return `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${dexNumber}.png`;
  };

  return (
    <div
      className={`bg-white border-2 rounded-lg shadow-lg p-4 transition-all duration-200 min-w-[320px] max-w-[400px] ${
        showPartyActions 
          ? 'border-blue-400 cursor-default' 
          : 'border-gray-300 cursor-pointer hover:shadow-xl hover:border-blue-400'
      }`}
      onClick={handleCardClick}
    >
      <div className="space-y-3">
        <div className="text-center">
          <h3 className="text-xl font-bold text-gray-900">
            {champion.name}
          </h3>
          <div className="flex items-center justify-center gap-2 text-sm text-gray-500">
            <span>#{champion.dexNumber.toString().padStart(3, '0')}</span>
            <span>•</span>
            <span>{champion.form}</span>
          </div>
        </div>

        <div className="flex flex-wrap justify-center gap-1">
          {champion.types.map((type, index) => (
            <button
              key={index}
              className={`px-3 py-1 text-xs text-white rounded-full font-semibold transition-colors ${typeColors[type] || 'bg-gray-400 hover:bg-gray-500'}`}
              onClick={(e) => {
                e.stopPropagation();
              }}
            >
              {type}
            </button>
          ))}
        </div>

        <div className="flex gap-4">
          <div className="flex-shrink-0">
            <img
              src={getPokemonImageUrl(champion.name, champion.dexNumber)}
              alt={champion.name}
              className="w-24 h-24 object-contain"
              onError={(e) => {
                (e.target as HTMLImageElement).src = 'https://via.placeholder.com/96x96?text=?';
              }}
            />
          </div>

          <div className="flex-1 space-y-2">
            <div>
              <div className="text-xs font-semibold text-gray-600 mb-1">Abilities:</div>
              <div className="flex flex-wrap gap-1">
                {Object.values(champion.abilities).slice(0, 2).map((ability, index) => {
                  const isHidden = Object.keys(champion.abilities)[index]?.toLowerCase() === 'h';
                  return (
                    <button
                      key={index}
                      className={`px-2 py-1 text-xs text-white rounded font-medium transition-colors ${getAbilityColor(ability)} ${isHidden ? 'opacity-75' : ''}`}
                      onClick={(e) => {
                        e.stopPropagation();
                      }}
                    >
                      {ability.replace(/-/g, ' ')}
                      {isHidden && ' (H)'}
                    </button>
                  );
                })}
              </div>
            </div>

            <div>
              <div className="text-xs font-semibold text-gray-600 mb-1">Combat Stats:</div>
              <div className="grid grid-cols-2 gap-1 text-xs">
                {combatStats.map((stat, index) => (
                  <div key={index} className="flex justify-between">
                    <span className="font-medium">{stat.name}:</span>
                    <span className="font-bold text-gray-700">{stat.value}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        <div className="flex justify-between text-xs text-gray-600 border-t pt-2">
          <span>HP: {stats.hp}</span>
          <span>Total: {stats.total}</span>
        </div>

              </div>
    </div>
  );
};

export default PokemonChampionCard;
